INSERT INTO plant_growth_log (
  logno, plantno, log_date, action, point_change, growth_change
) VALUES (
  plant_growth_log_seq.nextval, #{plantno}, SYSDATE, #{action}, #{point_change}, #{growth_change}
)

mapper.select:
SELECT * FROM plant_growth_log
WHERE plantno = #{plantno}
ORDER BY log_date DESC
